Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesBeforeDeadline()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so the [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceled()
    {
        // Arrange â€” handler that delays long enough to guarantee cancellation fires
        var handler = new FakeHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();

        // Act â€” cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler â€” no external mocking library needed
    private sealed class FakeHandler(
        string content, HttpStatusCode status, TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
            {
                await Task.Delay(delay, cancellationToken);
            }

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key points:**

- **`TestContext.CancellationToken`** â€” pass it to async calls in tests with `[Timeout]` so the timeout can cancel cooperatively instead of just aborting the thread.
- **`Assert.ThrowsExactlyAsync<T>`** â€” preferred over `[ExpectedException]`; it pins the exact exception type and lets you inspect it.
- **`FakeHandler`** â€” subclass `HttpMessageHandler` to control `HttpClient` without a mocking library; the `delay` parameter simulates slow responses for cancellation tests.
- **Sealed class + constructor-injected `TestContext`** â€” modern MSTest 3.6+ best practice.
